import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";

import Login from "./pages/Login";
import Register from "./pages/Register";
import ForgotPassword from "./pages/ForgotPassword";
import ResetPassword from "./pages/ResetPassword";

/* Dashboard Pages */

import DashboardLayout from "./pages/Dashboard/DashboardLayout";
import DashboardHome from "./pages/Dashboard/DashboardHome";
import Profit from "./pages/Dashboard/Profit";
import Loss from "./pages/Dashboard/Loss";
import Expense from "./pages/Dashboard/Expense";
import Weekly from "./pages/Dashboard/Weekly";
import Monthly from "./pages/Dashboard/Monthly";
import Analytics from "./pages/Dashboard/Analytics";
import Inflation from "./pages/Dashboard/Inflation";


/* Protected Route */

const PrivateRoute = ({ children }) => {
  const token = localStorage.getItem("token");
  return token ? children : <Navigate to="/login" />;
};


function App() {
  return (
    <Router>
      <Routes>

        {/* Authentication Pages */}

        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/forgot-password" element={<ForgotPassword />} />
        <Route path="/reset-password/:token" element={<ResetPassword />} />


        {/* Dashboard Layout (Protected) */}

        <Route
          path="/dashboard"
          element={
            <PrivateRoute>
              <DashboardLayout />
            </PrivateRoute>
          }
        >

          {/* Dashboard Pages */}

          <Route index element={<DashboardHome />} />
          <Route path="profit" element={<Profit />} />
          <Route path="loss" element={<Loss />} />
          <Route path="expense" element={<Expense />} />
          <Route path="weekly" element={<Weekly />} />
          <Route path="monthly" element={<Monthly />} />
          <Route path="inflation" element={<Inflation />} />
          <Route path="analytics" element={<Analytics />} />

        </Route>


        {/* Default */}

        <Route path="/" element={<Navigate to="/login" />} />

      </Routes>
    </Router>
  );
}

export default App;
